// To parse this JSON data, do
//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String module;
    String types;
    bool sideEffects;
    List<String> files;
    Exports exports;
    Scripts scripts;
    DevDependencies devDependencies;
    String repository;
    List<String> keywords;
    String author;
    String license;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.module,
        required this.types,
        required this.sideEffects,
        required this.files,
        required this.exports,
        required this.scripts,
        required this.devDependencies,
        required this.repository,
        required this.keywords,
        required this.author,
        required this.license,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        module: json["module"],
        types: json["types"],
        sideEffects: json["sideEffects"],
        files: List<String>.from(json["files"].map((x) => x)),
        exports: Exports.fromJson(json["exports"]),
        scripts: Scripts.fromJson(json["scripts"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        repository: json["repository"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        author: json["author"],
        license: json["license"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "module": module,
        "types": types,
        "sideEffects": sideEffects,
        "files": List<dynamic>.from(files.map((x) => x)),
        "exports": exports.toJson(),
        "scripts": scripts.toJson(),
        "devDependencies": devDependencies.toJson(),
        "repository": repository,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "author": author,
        "license": license,
    };
}

class DevDependencies {
    String typesNode;
    String mocha;
    String typescript;

    DevDependencies({
        required this.typesNode,
        required this.mocha,
        required this.typescript,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        typesNode: json["@types/node"],
        mocha: json["mocha"],
        typescript: json["typescript"],
    );

    Map<String, dynamic> toJson() => {
        "@types/node": typesNode,
        "mocha": mocha,
        "typescript": typescript,
    };
}

class Exports {
    Empty empty;
    String packageJson;

    Exports({
        required this.empty,
        required this.packageJson,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        empty: Empty.fromJson(json["."]),
        packageJson: json["./package.json"],
    );

    Map<String, dynamic> toJson() => {
        ".": empty.toJson(),
        "./package.json": packageJson,
    };
}

class Empty {
    Import purpleImport;
    Import require;

    Empty({
        required this.purpleImport,
        required this.require,
    });

    factory Empty.fromJson(Map<String, dynamic> json) => Empty(
        purpleImport: Import.fromJson(json["import"]),
        require: Import.fromJson(json["require"]),
    );

    Map<String, dynamic> toJson() => {
        "import": purpleImport.toJson(),
        "require": require.toJson(),
    };
}

class Import {
    String types;
    String importDefault;

    Import({
        required this.types,
        required this.importDefault,
    });

    factory Import.fromJson(Map<String, dynamic> json) => Import(
        types: json["types"],
        importDefault: json["default"],
    );

    Map<String, dynamic> toJson() => {
        "types": types,
        "default": importDefault,
    };
}

class Scripts {
    String test;

    Scripts({
        required this.test,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
    };
}
